"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import axios from "axios";
import { Plus, Search, Building, MapPin } from "lucide-react";
import { ProjectCreateModal } from "./ProjectCreateModal";

type Project = {
  id: string;
  code: string;
  name: string;
  developer: string;
  location: string;
  type: string;
  status: string;
  totalUnits: number;
  soldUnits: number;
};

export default function ProjectsPage() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      // Assuming Go API runs locally on 8081 for now 
      const res = await axios.get("http://localhost:8081/api/v1/projects");
      if (res.data.data) {
        setProjects(res.data.data);
      }
    } catch (error) {
      console.error("Error fetching projects", error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen p-8 max-w-6xl mx-auto">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Danh sách Dự án</h1>
          <p className="text-gray-500 mt-1 flex items-center">
            Có tổng cộng {projects.length} dự án trong hệ thống.
          </p>
        </div>
        <button onClick={() => setIsModalOpen(true)} className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-md font-medium hover:bg-blue-700 transition">
          <Plus className="w-5 h-5 mr-1" /> Thêm Dự Án
        </button>
      </div>

      <ProjectCreateModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSuccess={fetchProjects} 
      />

      <div className="bg-white border rounded-xl shadow-sm mb-6 p-2 flex items-center gap-2">
        <Search className="text-gray-400 w-5 h-5 ml-2" />
        <input 
          placeholder="Tìm theo tên dự án, chủ đầu tư, vị trí..." 
          className="flex-1 bg-transparent border-none outline-none py-2 px-2 text-sm"
        />
      </div>

      {loading ? (
        <div className="text-center py-20 text-gray-500">Đang tải dữ liệu...</div>
      ) : projects.length === 0 ? (
        <div className="text-center py-20 text-gray-500 bg-gray-50 border border-dashed rounded-xl">
          Không có dự án nào. Bấm Thêm Dự án để bắt đầu.
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {projects.map((p) => (
            <Link href={`/projects/${p.id}`} key={p.id} className="block">
              <div className="bg-white border rounded-xl p-5 shadow-sm hover:shadow-md transition-shadow cursor-pointer h-full border-l-4" style={{borderLeftColor: p.status === 'ACTIVE' ? '#22c55e' : '#94a3b8'}}>
                <div className="flex justify-between items-start mb-3">
                  <div className="flex items-center gap-2">
                    <div className="bg-blue-50 text-blue-700 font-bold px-2 py-0.5 rounded text-xs">{p.code}</div>
                    <span className={`text-xs px-2 py-0.5 rounded font-medium ${p.status === 'ACTIVE' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'}`}>
                      {p.status}
                    </span>
                  </div>
                </div>
                <h3 className="font-bold text-lg leading-tight mb-2">{p.name}</h3>
                
                <div className="space-y-2 mt-4">
                  <div className="flex items-center text-sm text-gray-600">
                    <Building className="w-4 h-4 mr-2" />
                    <span className="truncate">{p.developer || "Chưa cập nhật CĐT"}</span>
                  </div>
                  <div className="flex items-center text-sm text-gray-600">
                    <MapPin className="w-4 h-4 mr-2" />
                    <span className="truncate">{p.location || "Chưa có vị trí"}</span>
                  </div>
                </div>

                <div className="mt-5 pt-4 border-t flex justify-between items-center text-sm">
                  <div className="text-gray-500">
                    <span className="font-semibold text-gray-900">{p.soldUnits}</span> / {p.totalUnits} căn
                  </div>
                  <div className="w-24 bg-gray-100 rounded-full h-2">
                    <div 
                      className="bg-blue-600 h-2 rounded-full" 
                      style={{ width: `${p.totalUnits > 0 ? (p.soldUnits / p.totalUnits) * 100 : 0}%` }}
                    ></div>
                  </div>
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
